const raw = $input.first().json.body ?? $input.first().json;

const image_url    = String(raw.image_url    || '').trim();
const image_base64 = String(raw.image_base64 || '').trim();
const image_type   = String(raw.image_type   || 'image/jpeg').trim();
const fmt          = String(raw.output_format || 'json').toLowerCase();
const output_format = fmt === 'csv' ? 'csv' : 'json';
const request_id   = 'req_' + Date.now();
const timestamp    = new Date().toISOString();

const is_upload = image_base64.length > 100;
const has_image = is_upload || image_url.startsWith('http');

return {
  image_url,
  image_base64,
  image_type,
  output_format,
  request_id,
  timestamp,
  is_upload,
  has_image
};

const d = $input.first().json;

function detectMime(b64str) {
  try {
    const bin = Buffer.from(b64str.slice(0, 16), 'base64');
    if (bin[0] === 0xFF && bin[1] === 0xD8) return 'image/jpeg';
    if (bin[0] === 0x89 && bin[1] === 0x50) return 'image/png';
    if (bin[0] === 0x47 && bin[1] === 0x49) return 'image/gif';
    if (bin[0] === 0x52 && bin[1] === 0x49) return 'image/webp';
  } catch(e) {}
  return 'image/jpeg';
}

// Browser upload — base64 already present
if (d.is_upload === true && String(d.image_base64 || '').length > 100) {
  const b64  = d.image_base64;
  const mime = detectMime(b64);
  return {
    image_base64:  b64,
    media_type:    mime,
    image_url:     d.image_url,
    output_format: d.output_format,
    request_id:    d.request_id,
    timestamp:     d.timestamp,
    is_upload:     true
  };
}

// URL fetch
const url = d.image_url;
if (!url || !url.startsWith('http')) {
  throw new Error('No valid image_url. is_upload=' + d.is_upload + ' url=' + url);
}

const response = await $http.request({
  method: 'GET',
  url: url,
  encoding: null,
  followRedirect: true,
  followAllRedirects: true,
  rejectUnauthorized: false
});

const b64  = Buffer.from(response).toString('base64');
const mime = detectMime(b64);

return {
  image_base64:  b64,
  media_type:    mime,
  image_url:     url,
  output_format: d.output_format,
  request_id:    d.request_id,
  timestamp:     d.timestamp,
  is_upload:     false
};

// Prepare Image — pass through (fetch node already returns base64)
const d = $input.first().json;

return {
  image_base64:  d.image_base64,
  media_type:    d.media_type || d.image_type || 'image/jpeg',
  image_url:     d.image_url,
  output_format: d.output_format,
  request_id:    d.request_id,
  timestamp:     d.timestamp
};

const resp = $input.first().json;
const prev = $('Build Vision Body').first().json;

let text = '';
if (resp.content && resp.content[0]) {
  text = resp.content[0].text ?? '';
} else if (resp.choices && resp.choices[0]) {
  text = resp.choices[0].message?.content ?? '';
}

const cleaned = text.replace(/```json/gi,'').replace(/```/g,'').trim();

let equipment = [];
try {
  const parsed = JSON.parse(cleaned);
  equipment = Array.isArray(parsed) ? parsed : [parsed];
} catch(e) {
  const m = cleaned.match(/\[[\s\S]*\]/);
  if (m) {
    try { equipment = JSON.parse(m[0]); } catch(e2) {}
  }
}

return {
  equipment,
  image_url:     prev.image_url,
  output_format: prev.output_format,
  request_id:    prev.request_id,
  timestamp:     prev.timestamp
};

const resp = $input.first().json;
const prev = $('Build Summary Body').first().json;

let text = '';
if (resp.content && resp.content[0]) {
  text = resp.content[0].text ?? '{}';
} else if (resp.choices && resp.choices[0]) {
  text = resp.choices[0].message?.content ?? '{}';
}

const cleaned = text.replace(/```json/gi,'').replace(/```/g,'').trim();

let summary = {};
try { summary = JSON.parse(cleaned); }
catch(e) {
  summary = {
    total_units: (prev.equipment||[]).length,
    primary_vendor: 'Unknown',
    rack_type: 'Mixed',
    overall_confidence: 'low',
    key_observations: ['Summary parse error: ' + e.message]
  };
}

return {
  success:               true,
  equipment:             prev.equipment || [],
  summary,
  image_url:             prev.image_url,
  output_format:         prev.output_format,
  request_id:            prev.request_id,
  timestamp:             prev.timestamp,
  total_equipment_found: (prev.equipment||[]).length
};

const d = $input.first().json;
const eq = d.equipment ?? [];
const s  = d.summary   ?? {};

const esc = v => {
  const str = (v ?? '') + '';
  return str.includes(',') || str.includes('"') || str.includes('\n')
    ? '"' + str.replace(/"/g,'""') + '"' : str;
};

const rows = ['Position,Equipment Type,Brand,Model,Form Factor,Specifications,Ports,Max RAM,Storage,Year,Confidence,Notes'];
for (const i of eq) {
  rows.push([i.position,i.equipment_type,i.brand,i.model,i.form_factor,
    i.specifications,i.ports_interfaces,i.max_ram,i.storage_options,
    i.estimated_year,i.confidence,i.notes].map(esc).join(','));
}
rows.push('');
rows.push('SUMMARY');
rows.push('Total Equipment,' + esc(s.total_units ?? eq.length));
rows.push('Primary Vendor,'  + esc(s.primary_vendor));
rows.push('Rack Type,'       + esc(s.rack_type));
rows.push('Servers,'         + esc(s.server_count));
rows.push('Networking,'      + esc(s.networking_count));
rows.push('Storage,'         + esc(s.storage_count));
rows.push('Confidence,'      + esc(s.overall_confidence));

return { csv_content: rows.join('\n'), request_id: d.request_id };

const d = $input.first().json;
return {
  success:               true,
  request_id:            d.request_id,
  image_url:             d.image_url,
  processed_at:          d.timestamp,
  total_equipment_found: d.total_equipment_found,
  summary:               d.summary,
  equipment:             d.equipment,
  metadata: { model: 'claude-opus-4-6', gateway: 'Portkey', version: '1.0' }
};

const d = $input.first().json;

const b64   = d.image_base64 || '';
const mtype = d.media_type   || 'image/jpeg';

if (b64.length < 500) {
  throw new Error('image_base64 too short: ' + b64.length + ' chars. Image fetch failed or wrong media type. media_type=' + mtype);
}

return {
  body: JSON.stringify({
    model: 'claude-opus-4-6',
    max_tokens: 4096,
    messages: [{
      role: 'user',
      content: [
        {
          type: 'image',
          source: { type: 'base64', media_type: mtype, data: b64 }
        },
        {
          type: 'text',
          text: 'You are a data center infrastructure expert. Analyze this rack cabinet image carefully. Identify every piece of equipment you can see. Return ONLY a valid JSON array with no markdown. Each object must have these exact fields: position (e.g. U1, U2), equipment_type (Server/Switch/Router/Firewall/PDU/KVM/Patch Panel/UPS/Storage/Other), brand, model, form_factor (1U/2U/etc), specifications, ports_interfaces, max_ram, storage_options, estimated_year, confidence (high/medium/low), notes.'
        }
      ]
    }]
  }),
  image_url:     d.image_url,
  output_format: d.output_format,
  request_id:    d.request_id,
  timestamp:     d.timestamp,
  media_type:    mtype,
  b64_length:    b64.length
};

const d = $('Parse Vision Response').first().json;

return {
  body: JSON.stringify({
    model: 'claude-opus-4-6',
    max_tokens: 2048,
    messages: [{
      role: 'user',
      content: 'Summarize this rack equipment inventory as JSON with exactly these fields: total_units, primary_vendor, rack_type, estimated_compute_cores, estimated_max_ram_tb, server_count, networking_count, storage_count, other_count, estimated_rack_age, overall_confidence (high/medium/low), key_observations (array of 3 strings). Return ONLY valid JSON, no markdown. Equipment: ' + JSON.stringify(d.equipment)
    }]
  }),
  equipment:     d.equipment,
  image_url:     d.image_url,
  output_format: d.output_format,
  request_id:    d.request_id,
  timestamp:     d.timestamp
};

const ticketId = 'TKT-' + Date.now().toString(36).toUpperCase();
const timestamp = new Date().toISOString();

return [{
  json: {
    success: true,
    ticket_id: ticketId,
    title: items[0].json.title,
    description: items[0].json.description,
    priority: items[0].json.priority,
    category: items[0].json.category,
    status: 'open',
    created_at: timestamp,
    message: `Ticket ${ticketId} created successfully`
  }
}];

const alert = $input.first().json;

let alertCategory = 'unknown';
let priority = 'medium';
let targetAgent = 'incident';

if (alert.source === 'poweriq') {
  if (alert.type && alert.type.includes('temperature')) {
    alertCategory = 'thermal';
    priority = alert.value > 35 ? 'critical' : 'high';
    targetAgent = 'power';
  } else if (alert.type && alert.type.includes('power')) {
    alertCategory = 'power';
    priority = alert.percentage > 90 ? 'critical' : 'high';
    targetAgent = 'power';
  } else if (alert.type && alert.type.includes('humidity')) {
    alertCategory = 'environmental';
    targetAgent = 'power';
  } else {
    alertCategory = 'infrastructure';
    targetAgent = 'incident';
  }
} else if (alert.source === 'dctrack') {
  if (alert.type && alert.type.includes('asset')) {
    alertCategory = 'asset';
    targetAgent = 'asset';
  } else if (alert.type && alert.type.includes('capacity')) {
    alertCategory = 'capacity';
    targetAgent = 'capacity';
  } else {
    alertCategory = 'change';
    targetAgent = 'incident';
  }
}

const correlationId = 'alert-' + Date.now() + '-' + Math.random().toString(36).substr(2, 9);

return {
  json: {
    ...alert,
    alertCategory,
    priority,
    targetAgent,
    correlationId,
    processedAt: new Date().toISOString(),
    originalTimestamp: alert.timestamp || new Date().toISOString()
  }
};

const items = $input.all();
let agentResponse = {};
let originalAlert = {};

try {
  agentResponse = items[0].json || {};
  const parseNode = $('Parse and Classify Alert');
  if (parseNode && parseNode.first()) {
    originalAlert = parseNode.first().json || {};
  }
} catch (e) {
  agentResponse = items[0].json || {};
}

const needsAction = agentResponse.output && (
  agentResponse.output.severity === 'critical' ||
  agentResponse.output.createTicket === true ||
  (agentResponse.output.recommendations && agentResponse.output.recommendations.length > 0)
);

return {
  json: {
    correlationId: originalAlert.correlationId || 'unknown',
    originalAlert: originalAlert,
    agentAnalysis: agentResponse.output || agentResponse,
    needsAction: needsAction || false,
    processedAt: new Date().toISOString()
  }
};

// Collect data from all sources
const dctrackData = $('Get dcTrack Assets').first().json;
const poweriqData = $('Get Power IQ Devices').first().json;
const cmdbData = $('Get CMDB Assets').first().json;

// Parse assets from each source
const dctrackAssets = (dctrackData.searchResults?.items || dctrackData.data || []).map(item => ({
  id: item.id || item.tiId,
  name: item.tiName || item.name,
  serialNumber: item.tiSerialNumber || item.serialNumber,
  assetTag: item.tiAssetTag || item.assetTag,
  location: item.cmbLocation || item.location,
  cabinet: item.cmbCabinet || item.cabinet,
  status: item.cmbStatus || item.status,
  source: 'dctrack'
}));

const poweriqDevices = (poweriqData.devices || poweriqData.data || []).map(device => ({
  id: device.id,
  name: device.name,
  deviceId: device.device_id,
  cabinetId: device.cabinet_id,
  currentPowerWatts: device.current_power_watts || device.power || 0,
  lastReading: device.last_reading_time,
  source: 'poweriq'
}));

const cmdbAssets = (cmdbData.result || []).map(ci => ({
  sysId: ci.sys_id,
  name: ci.name,
  serialNumber: ci.serial_number,
  assetTag: ci.asset_tag,
  location: ci.location?.display_value || ci.location,
  cabinet: ci.u_cabinet,
  installStatus: ci.install_status,
  source: 'cmdb'
}));

// Create lookup maps
const dctrackBySerial = new Map();
dctrackAssets.forEach(a => {
  if (a.serialNumber) dctrackBySerial.set(a.serialNumber.toLowerCase(), a);
});

const cmdbBySerial = new Map();
cmdbAssets.forEach(a => {
  if (a.serialNumber) cmdbBySerial.set(a.serialNumber.toLowerCase(), a);
});

// Analysis results
const ghostAssets = [];
const missingFromDctrack = [];
const missingFromCmdb = [];
const locationMismatches = [];
const powerAnomalies = [];

// Ghost Detection: Assets in dcTrack with no/minimal power consumption
const GHOST_POWER_THRESHOLD = 5; // Watts
dctrackAssets.forEach(asset => {
  const powerData = poweriqDevices.find(p => 
    p.cabinetId === asset.cabinet || 
    p.name?.toLowerCase().includes(asset.name?.toLowerCase())
  );

  if (!powerData || powerData.currentPowerWatts < GHOST_POWER_THRESHOLD) {
    ghostAssets.push({
      ...asset,
      lastPowerReading: powerData?.currentPowerWatts || 0,
      reason: powerData ? 'Minimal power consumption' : 'No power data found',
      severity: 'medium'
    });
  }
});

// Missing from dcTrack: In CMDB but not in dcTrack
cmdbAssets.forEach(cmdbAsset => {
  if (cmdbAsset.serialNumber && !dctrackBySerial.has(cmdbAsset.serialNumber.toLowerCase())) {
    missingFromDctrack.push({
      ...cmdbAsset,
      reason: 'Asset in CMDB but not found in dcTrack',
      severity: 'high'
    });
  }
});

// Missing from CMDB: In dcTrack but not in CMDB
dctrackAssets.forEach(dcAsset => {
  if (dcAsset.serialNumber && !cmdbBySerial.has(dcAsset.serialNumber.toLowerCase())) {
    missingFromCmdb.push({
      ...dcAsset,
      reason: 'Asset in dcTrack but not found in CMDB',
      severity: 'medium'
    });
  }
});

// Location Mismatches: Same serial, different location
dctrackAssets.forEach(dcAsset => {
  if (dcAsset.serialNumber) {
    const cmdbAsset = cmdbBySerial.get(dcAsset.serialNumber.toLowerCase());
    if (cmdbAsset && cmdbAsset.location && dcAsset.location) {
      if (cmdbAsset.location.toLowerCase() !== dcAsset.location.toLowerCase()) {
        locationMismatches.push({
          serialNumber: dcAsset.serialNumber,
          name: dcAsset.name,
          dctrackLocation: dcAsset.location,
          cmdbLocation: cmdbAsset.location,
          severity: 'medium'
        });
      }
    }
  }
});

// Power Anomalies: Unusually high power consumption
const HIGH_POWER_THRESHOLD = 2000; // Watts
poweriqDevices.forEach(device => {
  if (device.currentPowerWatts > HIGH_POWER_THRESHOLD) {
    powerAnomalies.push({
      ...device,
      reason: 'Unusually high power consumption',
      severity: 'warning'
    });
  }
});

// Summary
const summary = {
  totalDctrackAssets: dctrackAssets.length,
  totalPoweriqDevices: poweriqDevices.length,
  totalCmdbAssets: cmdbAssets.length,
  ghostAssetsCount: ghostAssets.length,
  missingFromDctrackCount: missingFromDctrack.length,
  missingFromCmdbCount: missingFromCmdb.length,
  locationMismatchCount: locationMismatches.length,
  powerAnomalyCount: powerAnomalies.length,
  overallHealthScore: Math.max(0, 100 - (ghostAssets.length * 2) - (missingFromDctrack.length * 3) - (locationMismatches.length * 1)),
  runTimestamp: new Date().toISOString()
};

return {
  json: {
    summary,
    findings: {
      ghostAssets: ghostAssets.slice(0, 50), // Limit to 50 for processing
      missingFromDctrack: missingFromDctrack.slice(0, 50),
      missingFromCmdb: missingFromCmdb.slice(0, 50),
      locationMismatches: locationMismatches.slice(0, 50),
      powerAnomalies: powerAnomalies.slice(0, 20)
    },
    hasIssues: ghostAssets.length > 0 || missingFromDctrack.length > 0 || locationMismatches.length > 0
  }
};

