const tools = $json || [];
const rawTools = Array.isArray(tools) ? tools : (tools.tools || tools.data || []);
const userMessage = $('Input Validator').first().json.message;
const session_id = $('Input Validator').first().json.session_id;

const dctrack = [];
const poweriq = [];
const combined = [];

function formatParams(schema) {
  if (!schema || !schema.properties) return '';
  const props = schema.properties;
  const required = schema.required || [];
  const parts = [];
  for (const [key, val] of Object.entries(props)) {
    const v = val;
    const req = required.includes(key) ? ' (required)' : '';
    const type = v.type || 'any';
    const desc = v.description ? ` - ${v.description}` : '';
    parts.push(`    ${key}: ${type}${req}${desc}`);
  }
  return parts.length > 0 ? '\n' + parts.join('\n') : '';
}

for (const t of rawTools) {
  const name = t.name || '';
  const desc = t.description || '';
  const params = formatParams(t.inputSchema);
  const line = `- ${name}: ${desc}${params}`;
  if (name.startsWith('dctrack_')) dctrack.push(line);
  else if (name.startsWith('poweriq_')) poweriq.push(line);
  else if (name.startsWith('dcim_')) combined.push(line);
}

const toolCatalog = [
  `## dcTrack Tools (${dctrack.length})`,
  ...dctrack,
  '',
  `## Power IQ Tools (${poweriq.length})`,
  ...poweriq,
  '',
  `## Combined Analytics Tools (${combined.length})`,
  ...combined
].join('\n');

const systemPrompt = `You are a Sunbird DCIM AI assistant with access to dcTrack (asset management) and Power IQ (power monitoring) APIs.

You have ${rawTools.length} tools available. When the user asks about data center infrastructure, choose the right tool and respond with a JSON tool call.

RULES:
1. CRITICAL: If the user needs data, respond with ONLY raw JSON. No text before or after. No markdown code blocks. ONLY the JSON object or array.
2. Single tool call: {"tool": "tool_name", "args": {"param": "value"}}
3. Multiple tool calls (bulk operations): [{"tool": "tool_name", "args": {...}}, {"tool": "tool_name", "args": {...}}]
4. If the user is making conversation (greetings, thanks, general questions), respond with plain text.
5. Pick the most specific tool for the request.
6. For args, use the parameter names exactly as listed under each tool. Use numeric IDs where required.
7. For list/search operations: the server defaults to pageSize=1000 which returns up to 1000 items. Do NOT pass pageSize unless the user explicitly asks for fewer results. Only use a smaller pageSize if the user says "show me 10" or "limit to 50" etc.
8. dcTrack items use field names like tiName, cmbLocation, cmbCabinet, cmbStatus, tiClass.
9. Power IQ uses field names like name, id, pdu_id, severity.
10. Only include required parameters unless the user specifies additional filters.
11. For tools with no parameters listed, pass an empty args object: {"tool": "tool_name", "args": {}}
12. Cabinet creation requires: name, locationName (string), make (string), model (string). Example: {"tool": "dctrack_create_cabinet", "args": {"name": "CAB-01", "locationName": "AI-ROOM-01", "make": "Rittal", "model": "Orsted VX5311.116"}}
13. Item/PDU creation: ALWAYS include make and model (strings). Use cabinetName (string) NOT cabinetId. PDUs use tiClass="Rack PDU" and tiMounting="ZeroU". If user does not specify make/model, ask them. Example: {"tool": "dctrack_create_item", "args": {"tiName": "PDU-01", "tiClass": "Rack PDU", "cabinetName": "CAB-01", "tiMounting": "ZeroU", "make": "APC", "model": "AP8861"}}
14. Cabinet U-position map: When user asks about which U-positions are used/available, rack layout, or "show me U1 to U42", use dctrack_get_cabinet_u_map with cabinetName. Example: {"tool": "dctrack_get_cabinet_u_map", "args": {"cabinetName": "178B-02"}}
15. Cabinet items by name: When user asks "what items are in cabinet X", use dctrack_get_cabinet_items with cabinetName (string). Example: {"tool": "dctrack_get_cabinet_items", "args": {"cabinetName": "178B-02"}}
16. Model search: When user asks to find/search models by name, use dctrack_list_models with query parameter. Example: {"tool": "dctrack_list_models", "args": {"query": "C6100"}}
17. Find available cabinets: When user asks about cabinets with free space in a location, use dctrack_find_available_cabinets with locationName (string). Example: {"tool": "dctrack_find_available_cabinets", "args": {"locationName": "AI-ROOM-01", "minAvailableRUs": 4}}

LOCATION HANDLING:
CRITICAL: When a tool accepts locationName, ALWAYS pass the user's location text EXACTLY as they typed it. Do NOT rename, correct, or map location names — the server resolves them automatically. For example, if user says "ROOM-01", pass "ROOM-01" not "AI-ROOM-01". Different locations can have similar names (e.g., "ROOM 01" and "AI-ROOM-01" are completely different locations in different data centers).

13. IMPORTANT: For ANY question about cabinet capacity, free space, available U slots, or utilization, ALWAYS use dctrack_list_cabinets_with_capacity. NEVER use dctrack_get_cabinet_capacity for this \u2014 it only works for one cabinet at a time and requires an ID.\n\nAVAILABLE TOOLS:
${toolCatalog}`;

// Build messages array with conversation history
const history = $('Input Validator').first().json.history || [];
const messages = [{ role: 'system', content: systemPrompt }];

// Add conversation history (skip system messages, limit to last 10 turns)
const relevantHistory = history.filter(m => m.role === 'user' || m.role === 'assistant').slice(-10);
for (const msg of relevantHistory) {
  // Skip the last user message since we add it separately
  if (msg === relevantHistory[relevantHistory.length - 1] && msg.role === 'user') continue;
  messages.push({ role: msg.role, content: msg.content });
}

messages.push({ role: 'user', content: userMessage });

return { systemPrompt, userMessage, session_id, toolCount: rawTools.length, messages };

// Parse LLM response — robust JSON extractor with brace-counting
// Handles: clean JSON, text preamble, markdown code blocks, nested args
const MCP_BASE = 'http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080';
const response = $json;
const session_id = $('Input Validator').first().json.session_id;
const userMessage = $('Input Validator').first().json.message;
let content = '';

try {
  content = response.choices?.[0]?.message?.content || '';
} catch (e) {
  return { directAnswer: 'Sorry, I encountered an error processing your request.', toolName: null, toolResult: null, session_id, userMessage };
}

if (!content.trim()) {
  return { directAnswer: 'I did not get a response. Please try again.', toolName: null, toolResult: null, session_id, userMessage };
}

// === Robust JSON extractor using brace-counting ===
function extractBalancedJSON(text, startIdx) {
  const openChar = text[startIdx];
  let depth = 0;
  let inString = false;
  let escaped = false;
  for (let i = startIdx; i < text.length; i++) {
    const ch = text[i];
    if (escaped) { escaped = false; continue; }
    if (ch === '\\' && inString) { escaped = true; continue; }
    if (ch === '"') { inString = !inString; continue; }
    if (inString) continue;
    if (ch === '{' || ch === '[') depth++;
    if (ch === '}' || ch === ']') depth--;
    if (depth === 0) return text.substring(startIdx, i + 1);
  }
  return null;
}

function findToolCalls(text) {
  // Strip markdown code blocks
  let cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/gi, '').trim();

  // Strategy 1: Direct parse as array
  try {
    if (cleaned.startsWith('[')) {
      const parsed = JSON.parse(cleaned);
      if (Array.isArray(parsed) && parsed.length > 0 && parsed[0].tool) return parsed;
    }
  } catch(e) {}

  // Strategy 2: Direct parse as object
  try {
    if (cleaned.startsWith('{')) {
      const parsed = JSON.parse(cleaned);
      if (parsed.tool && typeof parsed.tool === 'string') return [parsed];
    }
  } catch(e) {}

  // Strategy 3: Find first [ containing "tool" and extract with brace-counting
  const arrayIdx = cleaned.indexOf('[');
  if (arrayIdx !== -1 && cleaned.indexOf('"tool"') > arrayIdx) {
    const candidate = extractBalancedJSON(cleaned, arrayIdx);
    if (candidate) {
      try {
        const parsed = JSON.parse(candidate);
        if (Array.isArray(parsed) && parsed.length > 0 && parsed[0].tool) return parsed;
      } catch(e) {}
    }
  }

  // Strategy 4: Find individual {"tool":...} objects with brace-counting
  const results = [];
  let searchFrom = 0;
  while (searchFrom < cleaned.length) {
    const toolKeyIdx = cleaned.indexOf('"tool"', searchFrom);
    if (toolKeyIdx === -1) break;
    let braceIdx = -1;
    for (let i = toolKeyIdx - 1; i >= searchFrom; i--) {
      if (cleaned[i] === '{') { braceIdx = i; break; }
      if (![' ', '\n', '\r', '\t'].includes(cleaned[i])) break;
    }
    if (braceIdx === -1) { searchFrom = toolKeyIdx + 1; continue; }
    const candidate = extractBalancedJSON(cleaned, braceIdx);
    if (candidate) {
      try {
        const parsed = JSON.parse(candidate);
        if (parsed.tool && typeof parsed.tool === 'string') {
          results.push(parsed);
          searchFrom = braceIdx + candidate.length;
          continue;
        }
      } catch(e) {}
    }
    searchFrom = toolKeyIdx + 1;
  }

  return results.length > 0 ? results : null;
}

const toolCalls = findToolCalls(content) || [];

if (toolCalls.length > 0) {
  const results = [];
  const allArgs = [];
  let lastName = '';

  for (const tc of toolCalls) {
    lastName = tc.tool;
    const toolArgs = tc.args || {};
    allArgs.push(toolArgs);
    try {
      const resp = await this.helpers.httpRequest({
        method: 'POST',
        url: MCP_BASE + '/tools/' + tc.tool,
        body: toolArgs,
        json: true,
        timeout: 120000,
      });
      results.push(resp);
    } catch (err) {
      results.push({ error: err.message || 'Tool execution failed' });
    }
  }

  const toolName = toolCalls.length === 1 ? lastName : lastName + ' (x' + toolCalls.length + ')';
  const fullResult = toolCalls.length === 1 ? JSON.stringify(results[0]) : JSON.stringify(results);
  const toolResult = fullResult.substring(0, 8000);
  const toolResultFull = fullResult.substring(0, 100000);
  const toolArgsOut = toolCalls.length === 1 ? allArgs[0] : allArgs;

  return {
    directAnswer: null,
    toolName,
    toolArgs: toolArgsOut,
    toolCount: toolCalls.length,
    toolResult,
    toolResultFull,
    session_id,
    userMessage
  };
} else {
  return {
    directAnswer: content,
    toolName: null,
    toolResult: null,
    session_id,
    userMessage
  };
}

