// Build OpenAI-compatible chat completion response
const parseData = $('Parse and Execute Tool').first().json;
let content = '';
let toolUsed = null;

try {
  if (parseData.toolName) {
    const summarizeResponse = $json;
    content = summarizeResponse?.choices?.[0]?.message?.content || 'Tool executed but summary unavailable. Raw tool: ' + parseData.toolName;
    toolUsed = parseData.toolName;
  } else {
    content = parseData.directAnswer || 'I can help you with data center infrastructure. Try asking about locations, cabinets, items, PDUs, sensors, or power readings.';
  }
} catch (e) {
  content = parseData.directAnswer || 'An error occurred while processing the response.';
}

return {
  id: 'chatcmpl-' + Date.now(),
  object: 'chat.completion',
  created: Math.floor(Date.now() / 1000),
  model: 'sunbird-dcim-assistant-v2',
  choices: [{
    index: 0,
    message: { role: 'assistant', content: content },
    finish_reason: 'stop'
  }],
