const response = $json;
let content = '';

// Handle cases where response is missing or malformed
try {
  content = response.choices?.[0]?.message?.content || '';
} catch (e) {
  return {
    success: false,
    templates: [],
    layout: null,
    clarification_needed: false,
    questions: [],
    message: '',
    error: 'Invalid response from LLM'
  };
}

// Check for HTML error response (starts with '<')
if (content.trim().startsWith('<') || (typeof response === 'string' && response.trim().startsWith('<'))) {
  return {
    success: false,
    templates: [],
    layout: null,
    clarification_needed: false,
    questions: [],
    message: '',
    error: 'LLM returned an error. Please try again with a smaller request.'
  };
}

// Check for empty response
if (!content || content.trim() === '') {
  return {
    success: false,
    templates: [],
    layout: null,
    clarification_needed: false,
    questions: [],
    message: '',
    error: 'Empty response from LLM. Please try again.'
  };
}

// Try to extract JSON template from the response
let templates = [];
let clarification_needed = true;

// Look for JSON in the response
const jsonMatch = content.match(/\{[\s\S]*"templates"[\s\S]*\}/);
if (jsonMatch) {
  try {
    const parsed = JSON.parse(jsonMatch[0]);
    if (parsed.templates && parsed.templates.length > 0) {
      templates = parsed.templates;
      clarification_needed = false;
    }
  } catch (e) {
    // JSON parse failed - continue to next method
  }
}

// Also try to find simple operation/object pattern
if (templates.length === 0) {
  const opMatch = content.match(/"Operation":\s*"(\w+)"[\s\S]*"Object":\s*"(\w+)"/);
  if (opMatch) {
    templates = [{
      Operation: opMatch[1],
      Object: opMatch[2]
    }];
    clarification_needed = false;
  }
}

return {
  success: !clarification_needed,
  templates: templates,
  layout: null,
  clarification_needed: clarification_needed,
  questions: [],
  message: content,
  error: null
};

const items = $input.all();
const mapItems = $('Map to MCP Tool').all();
const parseResponse = $('Parse Response').first().json;

// Check for parse error first
if (parseResponse.error) {
  return {
    id: "chatcmpl-" + Date.now(),
    object: "chat.completion",
    created: Math.floor(Date.now() / 1000),
    model: "dctrack-assistant",
    choices: [{
      index: 0,
      message: { role: "assistant", content: `❌ ${parseResponse.error}` },
      finish_reason: "stop"
    }],
    usage: { prompt_tokens: 10, completion_tokens: 20, total_tokens: 30 }
  };
}

const results = [];

for (let i = 0; i < items.length; i++) {
  const mcpData = items[i].json;
  const mapData = mapItems[i]?.json || {};
  const filterClass = mapData.filterClass;
  const filterLocation = mapData.filterLocation;
  const operation = mapData.operation;
  const object = mapData.object;
  let content = '';

  // Handle floor plan response
  if (object === 'FLOORPLAN' || mcpData.dxf) {
    const loc = mcpData.location || filterLocation;
    const count = mcpData.cabinetCount || 0;
    const filename = mcpData.filename || 'floorplan.dxf';
    const downloadUrl = `https://sunbird-mcp.apps.ocp419.crucible.iisl.com/download/floorplan/${encodeURIComponent(loc)}`;

    content = `✅ **Floor Plan Generated for ${loc}**\n\n`;
    content += `📊 **Cabinets:** ${count}\n`;
    if (mcpData.cabinets && mcpData.cabinets.length > 0) {
      content += `📍 **Layout:**\n`;
      mcpData.cabinets.forEach(c => {
        content += `  • ${c.name} (Row: ${c.row || 'N/A'}, Position: ${c.position || 'N/A'})\n`;
      });
    }
    content += `\n📥 **Download DXF:** [${filename}](${downloadUrl})\n`;
    content += `\n_Upload this file to dcTrack → Locations → ${loc} → Floor Map to view in 3D._`;
    results.push(content);
  }
  // Handle errors
  else if (mcpData.success === false || mcpData.errorList?.length > 0) {
    const errorMsg = mcpData.errorList?.join(', ') || mcpData.message || 'Operation failed';
    results.push(`❌ Error: ${errorMsg}`);
  }
  // Handle create/update success
  else if (mcpData.id || mcpData.item?.id) {
    const id = mcpData.id || mcpData.item?.id;
    const name = mcpData.tiName || mcpData.item?.tiName;
    results.push(`✅ Created: ${name} (ID: ${id})`);
  }
  // Handle delete success
  else if (mcpData.itemId) {
    results.push(`✅ Deleted item ID: ${mcpData.itemId}`);
  }
  // Handle items list
  else if (mcpData.items || mcpData.searchResults?.items) {
    let itemsList = mcpData.items || mcpData.searchResults.items;
    if (filterClass) {
      itemsList = itemsList.filter(i => i.tiClass === filterClass);
    }
    if (filterLocation) {
      itemsList = itemsList.filter(i => i.cmbLocation?.includes(filterLocation));
    }

    if (itemsList.length === 0) {
      content = `No ${filterClass || 'items'} found${filterLocation ? ' in ' + filterLocation : ''}.`;
    } else {
      const list = itemsList.slice(0, 20).map(i => `• ${i.tiName} (${i.tiClass}) - ${i.cmbStatus}`).join('\n');
      content = `**${filterClass || 'Items'}${filterLocation ? ' in ' + filterLocation : ''} in dcTrack:**\n\n${list}`;
      if (itemsList.length > 20) content += `\n\n...and ${itemsList.length - 20} more.`;
    }
    results.push(content);
  }
  // Handle locations
  else if (mcpData.locations) {
    const locs = mcpData.locations.map(l => `• ${l.tiLocationName} (${l.tiLocationCode})`).join('\n');
    results.push(`**Locations:**\n\n${locs}`);
  }
}

const finalContent = results.length > 0 ? results.join('\n') : 'Operation completed.';

return {
  id: "chatcmpl-" + Date.now(),
  object: "chat.completion",
  created: Math.floor(Date.now() / 1000),
  model: "dctrack-assistant",
  choices: [{
    index: 0,
    message: { role: "assistant", content: finalContent },
    finish_reason: "stop"
  }],
  usage: { prompt_tokens: 10, completion_tokens: 20, total_tokens: 30 }
};

const input = $json;
const templates = input.templates || [];

// Class mapping
const classMap = {
  'CABINET': 'Cabinet',
  'DEVICE': 'Device',
  'SERVER': 'Device',
  'NETWORK': 'Network',
  'SWITCH': 'Network',
  'RACK_PDU': 'Rack PDU',
  'PDU': 'Rack PDU',
  'PASSIVE': 'Passive',
  'DATA_PANEL': 'Data Panel',
  'HVAC': 'HVAC'
};

// Default models per class
const defaultModels = {
  'Cabinet': { make: 'Rittal', model: 'Orsted VX5311.116' },
  'Rack PDU': { make: 'CPI', model: 'Orsted EA-3019-C' },
  'Network': { make: 'Cisco Systems', model: 'Orsted N9K-C93180YC-FX' },
  'Device': { make: 'Cisco Systems', model: 'Orsted C8200L-1N-4T' }
};

// Process each template
const results = templates.map(template => {
  const operation = (template.Operation || 'LIST').toUpperCase();
  let object = (template.Object || 'ITEM').toUpperCase();

  // Check for type hint
  const typeHint = (template.type || '').toUpperCase();
  if (typeHint === 'SWITCH' || typeHint === 'NETWORK') object = 'NETWORK';
  if (typeHint === 'SERVER') object = 'DEVICE';

  const itemClass = classMap[object] || 'Device';

  // Build body
  const buildBody = () => {
    const body = {};
    if (template.id) body.id = template.id;
    if (template.name) body.name = template.name;
    if (template.location) body.location = template.location;
    if (template.status) body.status = template.status;
    body.make = template.make || defaultModels[itemClass]?.make;
    body.model = template.model || defaultModels[itemClass]?.model;
    body.class = itemClass;
    if (template.cabinet) body.cabinet = template.cabinet;
    if (template.uPosition) body.uPosition = template.uPosition;
    if (template.railsUsed) body.railsUsed = template.railsUsed || 'Both';
    if (template.cabinetSide) body.cabinetSide = template.cabinetSide;
    if (template.depthPosition) body.depthPosition = template.depthPosition;
    return body;
  };

  // Get tool config
  let tool, body;

  // Handle FLOORPLAN
  if (object === 'FLOORPLAN' || operation === 'GENERATE') {
    tool = 'dctrack_generate_floorplan';
    body = { location: template.location || 'AI-DEMO-DC' };
  }
  else if (object === 'LOCATION') {
    tool = 'dctrack_list_locations'; body = {};
  } 
  else if (object === 'MODEL') {
    tool = 'dctrack_list_models'; body = {};
  } 
  else if (['CREATE', 'ADD', 'INSTALL'].includes(operation)) {
    tool = 'dctrack_create_item'; body = buildBody();
  } 
  else if (['UPDATE', 'MODIFY'].includes(operation)) {
    tool = 'dctrack_update_item'; body = buildBody();
  } 
  else if (['DELETE', 'REMOVE'].includes(operation)) {
    tool = 'dctrack_delete_item'; body = buildBody();
  } 
  else {
    tool = 'dctrack_list_items'; body = {};
  }

  return {
    toolName: tool,
    toolUrl: `http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080/tools/${tool}`,
    toolBody: body,
    operation: operation,
    object: object,
    filterClass: classMap[object] || null,
    filterLocation: template.location || null,
    originalMessage: input.message
  };
});

// Return array of items for n8n to loop through
return results;

const body = $json.body || $json;

let message = '';
if (body.messages && Array.isArray(body.messages)) {
  const userMessage = body.messages.filter(m => m.role === 'user').pop();
  message = userMessage ? userMessage.content : '';
} else {
  message = body.message || '';
}

return {
  message: message || 'hello',
  session_id: body.session_id || 'session_' + Date.now(),
  timestamp: new Date().toISOString()
};

