const response = $json;
const userMessage = $('Input Validator1').item.json.message;

let category = 'GENERAL';

try {
  const content = response.choices?.[0]?.message?.content || '';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    category = (parsed.category || 'GENERAL').toUpperCase();
  }
} catch (e) {
  category = 'GENERAL';
}

// Validate category
const validCategories = ['LOCATION', 'CABINET', 'DEVICE', 'NETWORK', 'POWER', 
  'ENVIRONMENTAL', 'FACILITY', 'PASSIVE', 'MODEL', 'BULK', 'VALIDATION', 
  'WORKFLOW', 'REPORT', 'POWERIQ', 'ANALYSIS', 'GENERAL'];

if (!validCategories.includes(category)) {
  category = 'GENERAL';
}

return {
  category: category,
  message: userMessage,
  timestamp: $('Input Validator1').item.json.timestamp,
  session_id: $('Input Validator1').item.json.session_id
};

