  }
};

const categoryConfig = CATEGORY_PROMPTS[category] || CATEGORY_PROMPTS.GENERAL;

// Build the complete system prompt for Stage 2
const systemPrompt = `You are dcTrack DCIM assistant. Select the correct tool and arguments for the user's request.

${categoryConfig.tools}

${categoryConfig.examples}

RULES:
1. Respond with JSON ONLY - no markdown, no explanation outside JSON
2. Preserve full location paths with ' > ' separator
3. Use exact field names as shown
4. For greetings/unclear requests, use {"tool": "none", "args": {}, "message": "your helpful response"}

OUTPUT FORMAT:
{"tool": "tool_name", "args": {...}, "explanation": "brief description"}`;

return {
  category: category,
  message: message,
  systemPrompt: systemPrompt,
  timestamp: $json.timestamp,
  session_id: $json.session_id
};

const response = $json;
const category = $('Build Category-Specific Prompt1').item.json.category;
const userMessage = $('Build Category-Specific Prompt1').item.json.message;

let tool = null;
let args = {};
let explanation = '';
let directMessage = null;

try {
  const content = response.choices?.[0]?.message?.content || '';
  const match = content.match(/\{[\s\S]*\}/);
  if (match) {
    const parsed = JSON.parse(match[0]);
    tool = parsed.tool || null;
    args = parsed.args || {};
    explanation = parsed.explanation || '';
    directMessage = parsed.message || null;
  }
} catch (e) {
  // Parse failed - will be handled as direct response
  directMessage = "I'm sorry, I didn't understand that. Could you please rephrase your request?";
}

// Handle 'none' tool (greetings, help)
const isDirectResponse = (tool === 'none' || tool === null) || directMessage;

return {
  tool: tool,
  args: args,
  explanation: explanation,
  directMessage: directMessage,
  isDirectResponse: isDirectResponse && (tool === 'none' || tool === null),
  category: category,
  message: userMessage,
  timestamp: $('Build Category-Specific Prompt1').item.json.timestamp,
  session_id: $('Build Category-Specific Prompt1').item.json.session_id
};

const input = $json;

// MCP Server base URL
const MCP_BASE_URL = 'http://sunbird-mcp-server.iis-ai-ai.svc.cluster.local:8080';

const tool = input.tool;
const args = input.args || {};

if (!tool || tool === 'none') {
  return {
    skip: true,
    directMessage: input.directMessage,
    originalMessage: input.message
  };
}

return {
  skip: false,
  toolName: tool,
  toolUrl: `${MCP_BASE_URL}/tools/${tool}`,
  toolBody: args,
  explanation: input.explanation,
  category: input.category,
  originalMessage: input.message,
  timestamp: input.timestamp
};

const mcpResult = $json;
const prepData = $('Prepare MCP Call1').item.json;

// Handle errors
if (mcpResult.error) {
  return {
    response: {
      success: false,
      message: mcpResult.error,
      data: null
    },
    originalMessage: prepData.originalMessage,
    toolUsed: prepData.toolName,
    timestamp: prepData.timestamp
  };
}

// Format response based on tool/category
let message = '';
let formattedData = mcpResult;

const toolName = prepData.toolName || '';
const category = prepData.category || '';

// Format CABINET responses
if (toolName.includes('cabinet') || category === 'CABINET') {
  const items = mcpResult.searchResults?.items || mcpResult.items || mcpResult || [];
  const cabinets = Array.isArray(items) ? items : [];

  if (cabinets.length > 0) {
    message = `📦 **Found ${cabinets.length} Cabinet(s)**\n\n`;

    // Group by location
    const byLocation = {};
    cabinets.forEach(cab => {
      const loc = cab.cmbLocation || cab.location || 'Unknown Location';
      if (!byLocation[loc]) byLocation[loc] = [];
      byLocation[loc].push(cab);
    });

    for (const [location, cabs] of Object.entries(byLocation)) {
      message += `📍 **${location}**\n`;
      cabs.forEach(cab => {
        const name = cab.tiName || cab.name;
        const status = cab.cmbStatus || cab.status || 'N/A';
        message += `   • ${name} (Status: ${status})\n`;
      });
      message += '\n';
    }
  } else {
    message = '📦 No cabinets found.';
  }
}

// Format LOCATION responses
else if (toolName.includes('location') || category === 'LOCATION') {
  const locations = Array.isArray(mcpResult) ? mcpResult : (mcpResult.locations || mcpResult.items || []);

  if (locations.length > 0) {
    message = `🏢 **Found ${locations.length} Location(s)**\n\n`;
    locations.slice(0, 20).forEach(loc => {
      const name = loc.tiLocationName || loc.name || loc.locationName;
      const type = loc.tiLocationType || loc.type || '';
      message += `   • ${name}${type ? ` (${type})` : ''}\n`;
    });
    if (locations.length > 20) {
      message += `\n   ... and ${locations.length - 20} more`;
    }
  } else {
    message = '🏢 No locations found.';
  }
}

// Format DEVICE/ITEM responses
else if (toolName.includes('item') || toolName.includes('device') || category === 'DEVICE') {
  const items = mcpResult.searchResults?.items || mcpResult.items || [];

  if (items.length > 0) {
    message = `🖥️ **Found ${items.length} Item(s)**\n\n`;

    // Group by class
    const byClass = {};
    items.forEach(item => {
      const cls = item.tiClass || item.class || 'Other';
      if (!byClass[cls]) byClass[cls] = [];
      byClass[cls].push(item);
    });

    for (const [cls, clsItems] of Object.entries(byClass)) {
      message += `**${cls}s:**\n`;
      clsItems.slice(0, 10).forEach(item => {
        const name = item.tiName || item.name;
        const location = item.cmbLocation || item.location || '';
        const cabinet = item.cmbCabinet || item.cabinet || '';
        message += `   • ${name}`;
        if (cabinet) message += ` in ${cabinet}`;
        if (location && !cabinet) message += ` at ${location}`;
        message += '\n';
      });
      if (clsItems.length > 10) {
        message += `   ... and ${clsItems.length - 10} more ${cls}s\n`;
      }
      message += '\n';
    }
  } else {
    message = '🖥️ No items found.';
  }
}

// Format MODEL responses
else if (toolName.includes('model') || category === 'MODEL') {
  const models = mcpResult.searchResults?.items || mcpResult.items || mcpResult.models || [];

  if (models.length > 0) {
    message = `📋 **Found ${models.length} Model(s)**\n\n`;
    models.slice(0, 15).forEach(model => {
      const make = model.cmbMake || model.make || '';
      const name = model.tiModel || model.model || model.name;
      message += `   • ${make ? make + ' ' : ''}${name}\n`;
    });
    if (models.length > 15) {
      message += `\n   ... and ${models.length - 15} more`;
    }
  } else {
    message = '📋 No models found.';
  }
}

// Format POWER/PDU responses
else if (toolName.includes('power') || toolName.includes('pdu') || category === 'POWER' || category === 'POWERIQ') {
  const pdus = mcpResult.pdus || mcpResult.items || mcpResult || [];
  const items = Array.isArray(pdus) ? pdus : [];

  if (items.length > 0) {
    message = `⚡ **Found ${items.length} Power Device(s)**\n\n`;
    items.slice(0, 15).forEach(pdu => {
      const name = pdu.name || pdu.tiName || 'Unknown';
      const status = pdu.status || pdu.cmbStatus || '';
      message += `   • ${name}${status ? ` (${status})` : ''}\n`;
    });
  } else {
    message = '⚡ No power devices found.';
  }
}

// Format create/update/delete responses
else if (toolName.includes('create')) {
  const item = mcpResult.item || mcpResult;
  const name = item.tiName || item.name || 'Item';
  message = `✅ **Successfully Created**\n\n   • Name: ${name}\n   • ID: ${item.id || 'N/A'}`;
}

else if (toolName.includes('update')) {
  message = `✅ **Successfully Updated**`;
}

else if (toolName.includes('delete')) {
  message = `✅ **Successfully Deleted**`;
}

// Format floor plan responses
else if (toolName.includes('floorplan') || toolName.includes('floor_plan')) {
  message = `🗺️ **Floor Plan Generated**\n\n`;
  message += `   • Location: ${mcpResult.location || 'N/A'}\n`;
  message += `   • Cabinets: ${mcpResult.cabinetCount || 0}\n`;
  if (mcpResult.downloadPath) {
    message += `   • Download: ${mcpResult.downloadPath}`;
  }
}

// Default formatting
else {
  if (typeof mcpResult === 'object') {
    const count = mcpResult.count || mcpResult.total || 
                  (mcpResult.searchResults?.items?.length) || 
                  (Array.isArray(mcpResult) ? mcpResult.length : null);

    if (count !== null) {
      message = `✅ **Operation Complete**\n\n   Found ${count} result(s).`;
    } else {
      message = `✅ **Operation Complete**\n\n${JSON.stringify(mcpResult, null, 2).slice(0, 500)}`;
    }
  } else {
    message = `✅ **Operation Complete**`;
  }
}

return {
  response: {
    success: true,
    message: message,
    data: formattedData
  },
  originalMessage: prepData.originalMessage,
  toolUsed: prepData.toolName,
  category: prepData.category,
  timestamp: new Date().toISOString()
};

// Direct response (greetings, help, etc.)
const input = $json;

return {
  response: {
    success: true,
    message: input.directMessage || "Hello! I'm your dcTrack AI assistant. I can help you manage locations, cabinets, devices, power connections, and more. What would you like to do?",
    data: null
  },
  originalMessage: input.message,
  toolUsed: 'none',
  category: input.category,
  timestamp: new Date().toISOString()
};

// Merge responses from both paths
const items = $input.all();
return items[0].json;

const file = $input.first().json;

const fileId   = file.id   || file.fileId   || '';
const fileName = file.name || file.fileName || 'unknown.jpg';
const mimeType = file.mimeType || 'image/jpeg';

const allowed = ['image/jpeg','image/png','image/gif','image/webp','image/bmp','image/tiff'];
if (!allowed.includes(mimeType)) {
  throw new Error('Not an image — skipping: ' + fileName + ' (' + mimeType + ')');
}

const baseName  = fileName.replace(/\.[^/.]+$/, '');
const requestId = 'req_' + Date.now();
const ts        = new Date().toISOString().replace(/[:.]/g, '-').slice(0,19);

return [{ json: {
  file_id:    fileId,
  file_name:  fileName,
  base_name:  baseName,
  mime_type:  mimeType,
  request_id: requestId,
  timestamp:  new Date().toISOString(),
  csv_name:   'rack_inventory_' + baseName + '_' + ts + '.csv'
}}];

const downloaded  = $input.first();
const meta        = $('Extract File Info').first().json;

let base64Image = '';
let mediaType   = meta.mime_type || 'image/jpeg';

const binKeys = Object.keys(downloaded.binary || {});
if (binKeys.length > 0) {
  const key = binKeys[0];
  base64Image = downloaded.binary[key].data;
  mediaType   = downloaded.binary[key].mimeType || mediaType;
}

if (!base64Image) {
  throw new Error('Binary data missing after download for: ' + meta.file_name);
}

return [{ json: {
  ...meta,
  base64_image: base64Image,
  media_type:   mediaType
}}];

