const response  = $input.first().json;
const rawText   = response.content?.[0]?.text || '';
const meta      = $('Extract File Info').first().json;

let equipment = [];
try {
  const cleaned = rawText.replace(/```json\s*/g, '').replace(/```\s*/g, '').trim();
  equipment = JSON.parse(cleaned);
} catch (e) {
  const m = rawText.match(/(\[[\s\S]*\])/);
  if (m) {
    try { equipment = JSON.parse(m[1]); }
    catch (e2) { throw new Error('Cannot parse Claude JSON: ' + rawText.slice(0,300)); }
  } else {
    throw new Error('No JSON array found in Claude response: ' + rawText.slice(0,300));
  }
}

return [{ json: {
  ...meta,
  equipment_list: equipment,
  total_items:    equipment.length,
  parsed_at:      new Date().toISOString()
}}];

