const summaryRaw = $input.first().json;
const summaryText = summaryRaw.content?.[0]?.text || '{}';
const prevData = $('Parse Equipment List').first().json;

let summary = {};
try {
  const cleaned = summaryText.replace(/```json\s*/g,'').replace(/```\s*/g,'').trim();
  summary = JSON.parse(cleaned);
} catch (e) {
  summary = { parse_error: summaryText.slice(0,200) };
}

return [{ json: { ...prevData, summary } }];

const data      = $input.first().json;
const equipment = data.equipment_list || [];
const summary   = data.summary || {};

const esc = v => {
  const s = String(v ?? '');
  return (s.includes(',') || s.includes('"') || s.includes('\n'))
    ? '"' + s.replace(/"/g,'""') + '"'
    : s;
};

const headers = [
  'Position','Equipment Type','Brand','Model','Form Factor',
  'Specifications','Ports / Interfaces','Max RAM',
  'Storage Options','Est. Year','Confidence','Notes'
];

const dataRows = equipment.map(i => [
  esc(i.position), esc(i.equipment_type), esc(i.brand),
  esc(i.model),    esc(i.form_factor),    esc(i.specifications),
  esc(i.ports_interfaces), esc(i.max_ram), esc(i.storage_options),
  esc(i.estimated_year),   esc(i.confidence), esc(i.notes)
].join(','));

const summaryBlock = [
  '',
  '=== RACK SUMMARY ===',
  'Total Units,'          + esc(summary.total_units      ?? equipment.length),
  'Primary Vendor,'       + esc(summary.primary_vendor   ?? 'N/A'),
  'Servers,'              + esc(summary.server_count     ?? 'N/A'),
  'Networking Devices,'   + esc(summary.networking_count ?? 'N/A'),
  'Storage Devices,'      + esc(summary.storage_count    ?? 'N/A'),
  'Est. CPU Cores,'       + esc(summary.estimated_compute_cores ?? 'N/A'),
  'Est. Max RAM,'         + esc(summary.estimated_max_ram_tb    ?? 'N/A'),
  'Rack Age Era,'         + esc(summary.estimated_rack_age      ?? 'N/A'),
  'Confidence,'           + esc(summary.overall_confidence      ?? 'N/A'),
  'Key Observations,'     + esc((summary.key_observations || []).join(' | ')),
  '',
  'Source File,'          + esc(data.file_name),
  'Processed At,'         + esc(data.parsed_at),
  'Request ID,'           + esc(data.request_id)
];

const csv = [ headers.join(','), ...dataRows, ...summaryBlock ].join('\n');

return [{
  json: { ...data, csv_content: csv },
  binary: {
    csvFile: {
      data:     Buffer.from(csv).toString('base64'),
      mimeType: 'text/csv',
      fileName: data.csv_name
    }
  }
}];

const upload   = $input.first().json;
const data     = $('Build CSV File').first().json;

console.log('✅ Done | File: ' + data.file_name + ' | Items: ' + data.total_items + ' | CSV: ' + data.csv_name);

return [{ json: {
  success:          true,
  source_file:      data.file_name,
  request_id:       data.request_id,
  equipment_found:  data.total_items,
  csv_saved_as:     data.csv_name,
  drive_file_id:    upload.id || 'uploaded',
  output_folder:    'OUTPUT_FOLDER_ID',
  completed_at:     new Date().toISOString()
}}];
